      starterCode: "using System;\nusing System.IO;\nusing System.Text;\nusing System.Text.Json;\nusing System.Collections.Generic;\n\nclass Program\n{\n    public class Record\n    {\n        public string Name { get; set; } = \"\";\n        public int Score { get; set; }\n    }\n\n    static void Main()\n    {\n        var records = new List<Record>\n        {\n            new Record { Name = \"Allen\", Score = 90 },\n            new Record { Name = \"Bess\",  Score = 85 }\n        };\n\n        var options = new JsonSerializerOptions { WriteIndented = true };\n\n        try\n        {\n            // TODO: 1) 把 records 序列化成 JSON,写进 \"data.json\"(用 options)\n\n            // TODO: 2) 用 StringBuilder 拼一份报表:每行 \"name: score\",\n            //          末尾再写一行总分 \"Total: <sum>\"\n            var sb = new StringBuilder();\n            // ...\n\n            // TODO: 3) 把报表用 File.WriteAllText 写进 \"report.txt\"\n        }\n        catch (Exception ex)\n        {\n            // TODO: 4) 在 catch 里打印出错信息,别让程序裸崩\n        }\n    }\n}\n",
