      icon: "C#",
      objective: "写一个 async Task<int> ProcessAsync 方法，用 await File.ReadAllTextAsync 逐个读文件并累加字符数，最后返回总数。",
      starterCode: "using System;\nusing System.Collections.Generic;\nusing System.IO;\nusing System.Threading.Tasks;\n\nclass Program\n{\n    // TODO: 实现 ProcessAsync\n    //   - 遍历 files\n    //   - await File.ReadAllTextAsync 读每个文件\n    //   - 累加 text.Length\n    //   - 返回总字符数\n    static int ProcessAsync(IEnumerable<string> files)\n    {\n        // TODO: 改成 async Task<int>\n        return 0;\n    }\n\n    static void Main()\n    {\n        Console.WriteLine(\"async\");\n    }\n}\n",
